@click.command("routes", short_help="Show the routes for the app.")
@click.option(
    "--sort",
    "-s",
    type=click.Choice(("endpoint", "methods", "rule", "match", "domain")),
    default="endpoint",
    help=(
        'Method to sort routes by. "match" is the order that Flask will match '
        "routes when dispatching a request."
    ),
)
@click.option("--all-methods", is_flag=True, help="Show HEAD and OPTIONS methods.")
@with_appcontext
def routes_command(sort: str, all_methods: bool) -> None:
    """Show all registered routes with endpoints and methods."""

    rules = list(current_app.url_map.iter_rules())
    if not rules:
        click.echo("No routes were registered.")
        return

    ignored_methods = set(() if all_methods else ("HEAD", "OPTIONS"))

    # Check if any rules have domain/subdomain information
    host_matching = current_app.url_map.host_matching
    has_domain = any(
        rule.host if host_matching else rule.subdomain for rule in rules
    )

    # Prepare rows of data
    rows = []
    for rule in rules:
        methods = ", ".join(sorted(rule.methods - ignored_methods))  # type: ignore

        if has_domain:
            domain = rule.host if host_matching else rule.subdomain or ""
            # If subdomain is present and SERVER_NAME is configured, build full domain
            if domain and not host_matching and current_app.config.get("SERVER_NAME"):
                domain = f"{domain}.{current_app.config['SERVER_NAME']}"
            elif not domain and not host_matching and current_app.config.get("SERVER_NAME"):
                domain = current_app.config["SERVER_NAME"]

            row = [rule.endpoint, methods, domain, rule.rule]
        else:
            row = [rule.endpoint, methods, rule.rule]

        rows.append(row)

    # Sort the rows
    if sort == "endpoint":
        rows = sorted(rows, key=itemgetter(0))
    elif sort == "methods":
        rows = sorted(rows, key=itemgetter(1))
    elif sort == "rule":
        rows = sorted(rows, key=itemgetter(-1))
    elif sort == "domain":
        rows = sorted(rows, key=itemgetter(2 if has_domain else 0))
    # sort == "match" is already in the right order

    # Determine headers and widths
    if has_domain:
        headers = ("Endpoint", "Methods", "Subdomain" if not host_matching else "Host", "Rule")
    else:
        headers = ("Endpoint", "Methods", "Rule")

    # Calculate column widths
    widths = [max(len(str(row[i])) for row in rows) for i in range(len(headers))]
    widths = [max(len(h), w) for h, w in zip(headers, widths)]

    # Create format string
    row_format = "  ".join(f"{{{{0[{i}]:<{w}}}}}" for i, w in enumerate(widths))

    # Print output
    click.echo(row_format.format(headers).strip())
    click.echo(row_format.format(["-" * w for w in widths]))

    for row in rows:
        click.echo(row_format.format(row).rstrip())

